/**
 * 1. CAPTURA DE DADOS DA CONTA (Webhook2)
 */
let accountId = "";
let bankName = "";
let accountName = "";

try {
  // Tenta capturar do nó 'Webhook2' (Corrigido para W maiúsculo)
  const refNode = $('Webhook').first().json;
  const data = refNode.body || refNode;

  accountId = data.accountId || ""; 
  bankName = data.bankName || ""; 
  accountName = data.accountName || "";
} catch (e) {
  console.log("Aviso: Dados do nó 'Webhook2' não encontrados.");
}

// Fallback para o nó de código inicial se o webhook2 falhar
if (!accountId) {
  try {
    const backupNode = $('Code in JavaScript4').first().json;
    accountId = backupNode.accountId || "";
    bankName = bankName || backupNode.bankName || "Banco";
    accountName = accountName || backupNode.accountName || "Conta";
  } catch (e) {}
}

const nomeContaCompleto = `${bankName || "Banco"} - ${accountName || "Conta"}`;

/**
 * 2. PROCESSAMENTO DA SAÍDA DA IA
 */
// Aponta diretamente para o nó da IA
let raw = $('AI Agent PDF10').first().json.output;

// Limpa o bloco markdown (crases) que a IA envia
if (typeof raw === 'string') {
  raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();
}

let lista = [];

// Converte o texto limpo para um Array JSON de verdade
try {
  lista = JSON.parse(raw);
} catch (e) {
  return [{ json: { erro: "JSON Inválido", detalhe: e.message } }];
}

const chavesVistas = new Set();
const agora = new Date();
const mesAtual = agora.getMonth() + 1;
const anoAtual = agora.getFullYear();

/**
 * FUNÇÃO: formatarDataInteligente
 * Resolve o erro de Dezembro: se a compra é mes 12 e estamos no mes 2, o ano é o anterior.
 * (Atualizado: Agora lê meses em texto como "26 NOV")
 */
function formatarDataInteligente(dataStr) {
  if (!dataStr) return null;

  let limpa = dataStr.toString().toUpperCase().trim();

  // NOVO: Dicionário para converter meses do Nubank/Faturas em números
  const mesesTextuais = {
      "JAN": "01", "FEV": "02", "MAR": "03", "ABR": "04",
      "MAI": "05", "JUN": "06", "JUL": "07", "AGO": "08",
      "SET": "09", "OUT": "10", "NOV": "11", "DEZ": "12"
  };

  // NOVO: Se a data tem letras (ex: "26 NOV"), transforma em "26/11"
  for (const [nome, num] of Object.entries(mesesTextuais)) {
      if (limpa.includes(nome)) {
          let dia = limpa.replace(/[^\d]/g, ''); // Extrai apenas os números (o dia)
          if (dia.length > 0) {
              limpa = `${dia.padStart(2, '0')}/${num}`;
              break;
          }
      }
  }

  // Normaliza separadores
  limpa = limpa.replace(/-/g, '/');
  const partes = limpa.split('/');

  if (partes.length >= 2) {
    let d, m, a;

    if (partes.length === 2) {
      // Formato DD/MM (comum em faturas)
      [d, m] = partes.map(Number);
      a = anoAtual;
    } else {
      // Formato DD/MM/YYYY ou YYYY/MM/DD
      let p = partes.map(Number);
      if (p[0] > 1000) { [a, m, d] = p; } 
      else { [d, m, a] = p; }
    }

    // Proteção para anos de 2 dígitos enviados pela IA (ex: 26 vira 2026)
    if (a < 100) a += 2000;

    // Lógica de viragem de ano (Ex: Compra em 12 numa fatura de 02)
    if (m > (mesAtual + 1) && a >= anoAtual) {
      a = anoAtual - 1;
    }

    return `${a}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
  }
  return dataStr;
}

const processados = lista.map((item, index) => {
  // Tratamento de Valor (preserva decimais)
  let rawVal = item.v || item.Valor || item.valor || 0;
  let valorOriginal = (typeof rawVal === 'string') ? parseFloat(rawVal.replace(',', '.')) : parseFloat(rawVal);

  let descricao = (item.Descricao || "").toUpperCase().trim();
  let tipoIA = (item.Tipo || "despesa").toLowerCase();

  // Unificação de Sinal
  let valorFinal = Math.abs(valorOriginal);
  if (tipoIA === "despesa") {
    valorFinal = -Math.abs(valorOriginal);
  }

  // Datas Inteligentes
  const dataLancamento = formatarDataInteligente(item.Data_lancamento);
  const dataPagamento = formatarDataInteligente(item.Data_pagamento) || dataLancamento;

  return {
    ...item,
    account_id: accountId, // Ajustado para usar a variável segura lá de cima
    Conta: nomeContaCompleto,
    Valor: valorFinal,
    Descricao: descricao,
    Data_lancamento: dataLancamento,
    Data_pagamento: dataPagamento,
    id_conciliacao: `${descricao}-${valorFinal}-${index}`
  };
});

// Filtro de duplicidade (seguro para pedágios)
const dataFiltrada = processados.filter(item => {
    if (chavesVistas.has(item.id_conciliacao)) return false;
    chavesVistas.add(item.id_conciliacao);
    return true;
});

return dataFiltrada.map(item => ({ json: item }));

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
const webhookData = $('Webhook').first().json.body;

// Agora você extrai tudo de dentro da variável webhookData
const base64 = webhookData.file; 
const fileName = webhookData.fileName;
const userId = webhookData.userId;
const fileType = webhookData.fileType;

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    fileName: fileName,
    fileType: fileType,
    userId: userId
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      fileType
    )
  }
}];

const finalResults = [];
// Usamos o meio do dia para evitar problemas de fuso horário (D-1)
const hoje = new Date();
hoje.setHours(12, 0, 0, 0);
const hojeIso = hoje.toISOString().split('T')[0];

function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// 1. CAPTURA DE IDS (Garante funcionamento independente do caminho do Switch)
let userIdFixo = "";
let webhookData = {};
try {
  webhookData = $('Webhook').first().json.body;
  try { userIdFixo = $('Code in JavaScript1').item.json.userId; } 
  catch (e) { userIdFixo = $('Code in JavaScript4').item.json.userId; }
} catch (e) { userIdFixo = webhookData.userId || ""; }

const ownerIdCalculado = webhookData.ownerId || userIdFixo;

// 2. PROCESSAMENTO
for (const item of $input.all()) {
  const transacao = item.json;
  const descOriginal = (transacao.Descricao || "").toUpperCase();
  const parcelaIA = (transacao.p || "").toString().toUpperCase();

  const regex = /(\d+)\s*[\/\-de\s]+\s*(\d+)/i;
  const match = parcelaIA.match(regex) || descOriginal.match(regex);

  const dataLancamentoLimpa = transacao.Data_lancamento.includes('T') ? transacao.Data_lancamento.split('T')[0] : transacao.Data_lancamento;

  if (match) {
    const parcelaAtual = parseInt(match[1]);
    const totalParcelas = parseInt(match[2]);
    const descLimpa = descOriginal.replace(/\(\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)/gi, '').replace(regex, '').replace(/\s+/g, ' ').trim();
    const installmentGroupId = generateUUID();

    // Determina o ponto de partida do loop (se 1/X gera tudo, se 3/4 gera 3 e 4)
    const inicioLoop = parcelaAtual === 1 ? 0 : 0; 
    const fimLoop = totalParcelas - parcelaAtual;

    const dataBase = new Date(dataLancamentoLimpa + 'T12:00:00');

    for (let i = 0; i <= fimLoop; i++) {
      let dP = new Date(dataBase);
      dP.setMonth(dataBase.getMonth() + i);
      const dt = dP.toISOString().split('T')[0];

      // NOVA REGRA: Só é confirmado e tem data de pagamento se for HOJE ou PASSADO
      const isFuturo = dt > hojeIso;

      finalResults.push({
        json: {
          ...transacao,
          Descricao: `${descLimpa} (${parcelaAtual + i}/${totalParcelas})`,
          Data_lancamento: dt,
          userId: userIdFixo,
          accountId: webhookData.accountId,
          ownerId: ownerIdCalculado,
          // Regras solicitadas:
          confirmed: !isFuturo, 
          paymentDate: isFuturo ? null : webhookData.paymentDate,
          pending_review: true, // Todas as parcelas nascem para revisão
          installment_group_id: installmentGroupId,
          installment_number: parcelaAtual + i,
          total_installments: totalParcelas
        }
      });
    }
    continue;
  }

  // ITEM À VISTA (Normal)
  const dataFinalIso = new Date(dataLancamentoLimpa + 'T12:00:00').toISOString().split('T')[0];
  const isFuturoSimples = dataFinalIso > hojeIso;

  finalResults.push({
    json: {
      ...transacao,
      Data_lancamento: dataFinalIso,
      userId: userIdFixo,
      accountId: webhookData.accountId,
      ownerId: ownerIdCalculado,
      paymentDate: isFuturoSimples ? null : webhookData.paymentDate,
      confirmed: !isFuturoSimples,
      pending_review: false, // Itens comuns podem entrar como false ou conforme sua preferência
      installment_group_id: null,
      installment_number: null,
      total_installments: null
    }
  });
}

return finalResults;

/**
 * CÓDIGO UNIFICADO E ROBUSTO PARA EXTRATO (COM SUPORTE A NEUTRO)
 */

// 1. CAPTURA DE DADOS DA CONTA (Webhook2)
let accountId = "";
let nomeContaCompleto = "Conta - BTG Pactual";

try {
  const refNode = $('Webhook').first().json;
  const data = refNode.body || refNode.query || {};
  accountId = data.accountId || "";
  let bankName = data.bankName || "Banco";
  let accountName = data.accountName || "Conta";
  nomeContaCompleto = `${bankName} - ${accountName}`;
} catch (e) {}

// 2. CAPTURA E LIMPEZA DA IA
let raw = $('AI Agent PDF4').first().json.output || "";
if (typeof raw === 'string') {
  raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();
}

let lista = [];
try {
  lista = JSON.parse(raw);
} catch (e) {
  return [{ json: { erro: "JSON Inválido. A IA falhou na formatação.", detalhe: e.message } }];
}

const chavesVistas = new Set();
const agora = new Date();
const anoAtual = agora.getFullYear();

// Função que trata a Data
function formatarDataInteligente(dataStr) {
  if (!dataStr) return new Date().toISOString().split('T')[0];
  let limpa = dataStr.toString().toUpperCase().trim().replace(/-/g, '/');
  const partes = limpa.split('/');

  if (partes.length >= 2) {
    let d = Number(partes[0]);
    let m = Number(partes[1]);
    let a = partes.length === 3 ? Number(partes[2]) : anoAtual;
    if (a < 100) a += 2000;
    // Adiciona o meio-dia (T12:00:00) para blindar contra o fuso horário (GMT-3)
    return `${a}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}T12:00:00`;
  }
  return dataStr;
}

// 3. PROCESSAMENTO E LIMPEZA DE DADOS
const processados = lista.map((item, index) => {
  let dataOriginal = item.Data || item.Data_lancamento || item.d || "";
  let descricao = (item.Descricao || item.t || "").toString().toUpperCase().trim();
  let tipoIA = (item.Tipo || item.tipo || item.s || "despesa").toString().toLowerCase();
  let categoriaIA = (item.Categoria || item.c || "").toString().toLowerCase();

  // Tratamento super seguro de valor (Lida com R$, espaços, vírgulas e pontos)
  let rawVal = item.Valor !== undefined ? item.Valor : (item.v || item.valor || 0);
  let valorLimpo = rawVal;
  if (typeof rawVal === 'string') {
      valorLimpo = valorLimpo.replace(/[R$\s]/ig, ''); // Remove R$ e espaços
      if (valorLimpo.includes(',') && valorLimpo.includes('.')) {
          valorLimpo = valorLimpo.replace(/\./g, '').replace(',', '.'); // Ex: 3.200,00 vira 3200.00
      } else if (valorLimpo.includes(',')) {
          valorLimpo = valorLimpo.replace(',', '.'); // Ex: 3200,00 vira 3200.00
      }
  }
  let valorFinal = parseFloat(valorLimpo) || 0;

  // Ajuste de Sinal (+ ou -)
  if (tipoIA === "despesa" || tipoIA === "-") {
      valorFinal = -Math.abs(valorFinal);
  } else if (tipoIA === "receita" || tipoIA === "+" || tipoIA === "neutro") {
      valorFinal = Math.abs(valorFinal);
  }

  // Reforço de segurança pela descrição (ajusta o sinal com base nas palavras)
  if (descricao.includes('ENVIADO') || descricao.includes('PAGAMENTO') || descricao.includes('DEBITO')) {
      valorFinal = -Math.abs(valorFinal);
  } else if (descricao.includes('RECEBIDO') || descricao.includes('CREDITO')) {
      valorFinal = Math.abs(valorFinal);
  }

  let dataTransacao = formatarDataInteligente(dataOriginal);

  // === A MÁGICA DO NEUTRO ACONTECE AQUI ===
  let categoriasNeutras = ["reembolsos", "resgate-investimentos", "estorno"];
  let tipoFinal = valorFinal < 0 ? "despesa" : "receita";

  // Se a IA disse que é neutro, OU a categoria for neutra, OU a descrição acusar estorno/reembolso:
  if (tipoIA === "neutro" || categoriasNeutras.includes(categoriaIA) || descricao.includes('ESTORNO') || descricao.includes('REEMBOLSO')) {
      tipoFinal = "neutro";
  }
  // ==========================================

  return {
    ...item,
    account_id: accountId,
    Conta: nomeContaCompleto,
    Data_lancamento: dataTransacao,
    Data_pagamento: dataTransacao,
    Descricao: descricao,
    Valor: valorFinal,
    Tipo: tipoFinal, // Vai assumir o neutro perfeitamente agora!
    Categoria: categoriaIA || null
  };
});

// 4. FILTRO DE DUPLICIDADE (O index permite transações idênticas reais)
const dataFiltrada = processados.filter((item, index) => {
  const chaveUnica = `${item.Descricao}-${item.Valor}-${item.Data_pagamento}-${index}`;
  if (chavesVistas.has(chaveUnica)) return false;
  chavesVistas.add(chaveUnica);
  return true;
});

return dataFiltrada.map(item => ({ json: item }));

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
const webhookData = $('Webhook').first().json.body;

// Agora você extrai tudo de dentro da variável webhookData
const base64 = webhookData.file; 
const fileName = webhookData.fileName;
const userId = webhookData.userId;
const fileType = webhookData.fileType;

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    fileName: fileName,
    fileType: fileType,
    userId: userId
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      fileType
    )
  }
}];
